const getTrendingWithCounts = `-- name: GetTrendingWithCounts :many
SELECT
    a.anilist_id,
    a.title_romaji,
    a.title_english,
    a.title_native,
    a.title_chinese,
    a.cover_image_url,
    a.cover_image_color,
    a.poster_accent,
    a.average_score,
    a.bangumi_score,
    a.episodes,
    a.season,
    a.season_year,
    a.status,
    a.format,
    a.description,
    s.watcher_count
FROM anime_cache a
JOIN (
    SELECT anilist_id, count(*)::bigint AS watcher_count
    FROM subscriptions
    WHERE status = 'watching'
    GROUP BY anilist_id
    ORDER BY count(*) DESC
    LIMIT 20
) s ON s.anilist_id = a.anilist_id
ORDER BY s.watcher_count DESC
LIMIT $1
`

